    return render_page(body, req_id=req_id, req=req, req_opts=_ct307_req_options(reqs, req_id), posts=posts, bloqueado=bloqueado, badge=_ct_badge306, nav=_ct_nav306('postulantes', req_id), title='Postulantes')

